class UnionFind {
    constructor(size) {
        this.parent = new Array(size);
        this.rank = new Array(size);
        for (let i = 0; i < size; i++) {
            this.parent[i] = i;
            this.rank[i] = 1;
        }
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const rootX = this.find(x);
        const rootY = this.find(y);
        if (rootX === rootY) return false;

        if (this.rank[rootX] > this.rank[rootY]) {
            this.parent[rootY] = rootX;
            this.rank[rootX] += this.rank[rootY];
        } else {
            this.parent[rootX] = rootY;
            this.rank[rootY] += this.rank[rootX];
        }
        return true;
    }

    getCount() {
        const roots = new Set();
        for (let i = 0; i < this.parent.length; i++) {
            roots.add(this.find(i));
        }
        return roots.size;
    }
}

function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    const uf = new UnionFind(n);
    let left = 0;
    let right = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let result = 0;

    // Check if initial components are already >= k
    const initialUf = new UnionFind(n);
    for (const [u, v, time] of edges) {
        initialUf.union(u, v);
    }
    if (initialUf.getCount() >= k) {
        return 0;
    }

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const tempUf = new UnionFind(n);
        for (const [u, v, time] of edges) {
            if (time > mid) {
                tempUf.union(u, v);
            }
        }
        if (tempUf.getCount() >= k) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return result;
}

