import scala.collection.mutable

class UnionFind(size: Long) {
    private val parent = Array.range(0, size.toInt)
    private val rank = Array.fill(size.toInt)(1)

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Boolean = {
