            rank(rootX) += rank(rootY)
        } else {
            parent(rootX) = rootY
            rank(rootY) += rank(rootX)
        }
        true
    }

    def getCount(): Int = {
        val roots = mutable.Set[Int]()
        for (i <- 0 until size.toInt) {
            roots.add(find(i))
        }
        roots.size
    }
}

