import scala.collection.mutable

class UnionFind(size: Int) {
  private val parent = Array.range(0, size)
  private val rank = Array.fill(size)(1)

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Boolean = {
    val rootX = find(x)
    val rootY = find(y)
    if (rootX == rootY) return false

    if (rank(rootX) > rank(rootY)) {
      parent(rootY) = rootX
      rank(rootX) += rank(rootY)
    } else {
      parent(rootX) = rootY
      rank(rootY) += rank(rootX)
    }
    true
  }

  def getCount(): Int = {
    val roots = mutable.Set[Int]()
    for (i <- 0 until size) {
      roots.add(find(i))
    }
    roots.size
  }
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val sortedEdges = edges.sortBy(_(2))
  val uf = new UnionFind(n.toInt)
  var left = 0L
  var right = if (edges.nonEmpty) edges.map(_(2)).max else 0L
  var result = 0L

  // Check if initial components are already >= k
  val initialUf = new UnionFind(n.toInt)
  for (edge <- edges) {
    initialUf.union(edge(0).toInt, edge(1).toInt)
  }
  if (initialUf.getCount() >= k) {
    return 0L
  }

  while (left <= right) {
    val mid = (left + right) / 2
    val tempUf = new UnionFind(n.toInt)
    for (edge <- edges) {
      if (edge(2) > mid) {
        tempUf.union(edge(0).toInt, edge(1).toInt)
      }
    }
    if (tempUf.getCount() >= k) {
      result = mid
      right = mid - 1
    } else {
      left = mid + 1
    }
  }
  result
}
